import{_ as t,o as p,c as r,ag as i}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/%E5%9B%BE1.ukq_Q5SH.jpg",a="/kaiping-reports/assets/%E5%9B%BE2.Co94ZlUi.jpg",_="/kaiping-reports/assets/%E5%9B%BE3.BYAD7T9B.jpg",e="/kaiping-reports/assets/%E5%9B%BE4.C338l6fx.jpg",n="/kaiping-reports/assets/%E5%9B%BE5.BhlLEchG.jpg",c="/kaiping-reports/assets/%E5%9B%BE6.DFoHIUzN.jpg",g="/kaiping-reports/assets/%E5%9B%BE7.C6mpA82C.jpg",m="/kaiping-reports/assets/%E5%9B%BE8.yS55BKS6.jpg",B="/kaiping-reports/assets/%E5%9B%BE9.HNyQ0PLH.jpg",E="/kaiping-reports/assets/%E5%9B%BE10.CGcvd1xq.jpg",l="/kaiping-reports/assets/%E5%9B%BE11.D3Ouunfm.jpg",x=JSON.parse('{"title":"开平立园泮文楼建造材料构造与尺度人体感知调研报告","description":"","frontmatter":{"title":"开平立园泮文楼建造材料构造与尺度人体感知调研报告"},"headers":[],"relativePath":"reports/孙李源/孙李源_调研报告.md","filePath":"reports/孙李源/孙李源_调研报告.md"}'),k={name:"reports/孙李源/孙李源_调研报告.md"};function d(j,s,f,u,S,C){return p(),r("div",null,[...s[0]||(s[0]=[i('<p>开平立园泮文楼建造材料构造与尺度人体感知调研报告</p><p>摘要： 开平近代侨乡建筑融合中西文化与新式建造技术，立园泮文楼是其中的典型代表。本次调研围绕材料构造和尺度人体感知两大方向，通过实地观测分析，发现泮文楼采用钢筋混凝土主体、中西材料结合、新旧工艺并用的建造方式，尺度设计符合人体需求，兼顾了地域气候、审美与居住舒适感，为侨乡建筑智慧的现代运用提供了实证。</p><p>关键词：开平立园；泮文楼；建造材料；构造技术；尺度设计；人体感知；侨乡建筑</p><p>一、研究背景与引言 开平作为著名侨乡，在20世纪初形成了以碉楼、华侨园林、骑楼为代表的近代建筑体系，其核心特征是西洋建筑技术引入、中式营造理念传承、岭南地域气候适配三者的深度融合。立园由旅美华侨谢维立主持兴建，是开平华侨园林的巅峰之作，园区内泮文楼为园主兄长谢维文的居住别墅，与泮立楼、毓培别墅共同构成别墅区核心组团，建筑年代为20世纪20-30年代，属于两层中西合璧式居住建筑。 本次调研依照于建筑考察设定的观察体系，聚焦建造材料与构造、尺度与人体感知两大核心方向，摒弃泛化的文化叙事，以实证观测、数据记录、体感分析为手段，还原分析泮文楼的物质营造逻辑与空间感知特征。调研采用现场细部拍摄、构造草图标注、尺度参照物记录、空间体感体验感受等方法，确保数据真实、结论严谨，最终形成符合建筑史调研要求的调研报告。 <img src="'+o+'" alt="图1：泮文楼"><img src="'+a+'" alt="图2：泮文楼"></p><p>二、泮文楼建筑基本概况 泮文楼位于开平塘口镇立园别墅区核心区位，紧邻泮立楼，是立园六栋别墅中形制规整、保存完好的代表建筑。建筑主体为两层钢筋混凝土结构，整体风格以西式古典柱廊、拱券为主体形态，屋顶采用中式绿色琉璃瓦歇山顶，是典型的西式骨架、中式屋顶的侨乡建筑范式。 建筑原始功能为家庭居住，空间布局包含客厅、卧室、储物间、阳台等功能单元，无防御性碉楼特征，纯以居住舒适为核心目标。作为立园别墅区的重要组成部分，泮文楼不追求夸张的造型与装饰，而是以材料实用、构造简洁、尺度宜人为特点，更贴近普通华侨的居住需求，是研究近代开平侨乡民居营造技术的典型样本。</p><p>三、泮文楼建造材料与构造分析 建造材料与构造是建筑的核心，直接影响建筑耐用性、实用性和外观。本次通过现场观察，从结构材料、立面材料、构造连接三方面解析泮文楼。 3.1 结构材料：主体钢筋混凝土，内部砖木辅助 现场可见，泮文楼主体为钢筋混凝土框架，梁柱、楼板都是混凝土，承重结构清晰，底层没有厚重承重墙，空间分隔更灵活。这种材料抗风、防雨、防潮、防白蚁，适配岭南多雨潮湿的环境。 建筑内部隔断用青砖砌筑，搭配木梁、木楼板，能减轻建筑自重；屋顶基层可见木椽子、木望板，用来支撑中式琉璃瓦。整体是主体用现代材料、局部用传统材料的搭配，结实又经济。 3.2 立面材料：主体朴素，细节中西混搭 泮文楼外墙主体是水泥石灰抹灰，做仿石处理，耐风雨、成本低。 装饰集中在细节处：檐口、窗套、栏杆有进口彩色马赛克瓷砖；柱础、台阶用花岗岩，坚固耐磨；屋顶铺绿色中式琉璃瓦。整体墙面简洁，细部精致，中西材料搭配明显，是侨乡建筑的典型特征。 3.3 构造连接：现浇工艺与传统砌筑结合 屋面采用分层构造，木基层上铺设琉璃瓦，隔热防水效果好。所有构造做法都以牢固、耐用、适应气候为目的，实用简洁。 <img src="'+_+'" alt="图3：构造细节"><img src="'+e+'" alt="图4：材料分析"><img src="'+n+'" alt="图5：立面材料"><img src="'+c+'" alt="图6：装饰细节"></p><p>四、泮文楼尺度与人体感知分析 尺度是建筑与人体互动的核心媒介，直接影响空间使用效率与心理感受。本次调研从建筑高度与层数比例、门窗尺度、院落围合尺度三个维度，结合人体工程学与空间体感，解析泮文楼的尺度设计逻辑。 4.1 建筑高度与层数比例：竖向宜人尺度，视觉协调 泮文楼为两层建筑，总高度约8.5米，底层层高4.0米，二层层高3.8米，远高于传统岭南民居（传统民居层高约2.6-3.0米）。高层高设计核心目的是适配岭南气候，提升室内通风散热效率，同时避免低矮空间带来的压抑感。 建筑立面高宽比约1:1.8，横向舒展、竖向挺拔，西式方形壁柱强化竖向线条，中式琉璃瓦屋顶平缓出檐，压低视觉重心，形成“挺拔而不突兀、舒展而不松散”的视觉效果。从人体站立视角观测，建筑高度与人的视线高度形成舒适比例，无压迫感、无疏离感，符合居住建筑的宜人尺度要求。 4.2 门窗尺度：人体工程学适配，功能与感知统一 泮文楼门窗尺度严格遵循人体通行、视线采光、空间体感三大原则。入户主门尺度为高2.8米、宽1.2米，满足人体自由通行与家具搬运需求，门洞高度适配人体站立视线，顶部与屋顶线条衔接，视觉上延伸空间高度。 外窗以长方形落地窗与高侧窗为主，窗高2.1米、宽1.6米，窗底边距地0.9米，恰好适配人体坐姿与站姿的自然视线，采光面充足，室内通透感极强。门窗高宽比约1.7:1，竖向修长的比例契合西洋建筑美学，同时增大通风面积，提升岭南夏季室内舒适度。从人体感知来看，门窗尺度既满足功能需求，又让室内空间显得开阔明亮，无狭小局促的心理感受。 4.3 院落与建筑围合尺度：半开放空间，体感舒适 泮文楼隶属于立园别墅区小庭院空间，庭院面宽约12米、进深约15米，建筑与庭院边界距离3-4米，形成半开放围合空间。庭院步道宽1.5米，适配双人并行的人行尺度，动线流畅无阻碍；庭院内绿植、栏杆低矮，不遮挡视线，既保证居住私密性，又与立园整体园林空间连通。 从人体感知角度，庭院尺度适中，行走、停留、观景均无局促感，围合感与开敞性平衡，心理感受轻松舒缓。建筑与庭院的尺度配比，实现了“私密居住”与“园林观景”的融合，是华侨园林“园宅一体”理念的尺度表达。 <img src="'+g+'" alt="图7：尺度感知"><img src="'+m+'" alt="图8：空间分析"><img src="'+B+'" alt="图9：院落围合"><img src="'+E+'" alt="图10：建筑与环境"><img src="'+l+'" alt="图11：调研记录"></p><p>五、结论 泮文楼的材料构造与尺度设计，并非单纯的技术堆砌，而是地域适配、文化表达、人体感知三者的深度融合。在材料构造层面，钢筋混凝土解决岭南气候难题，中西材料混搭实现文化认同，构造工艺兼顾安全与效率，是华侨“务实、兼容、创新”精神的物质体现；在尺度设计层面，所有尺寸均以人体工程学为基础，高层高适配气候，宜人尺度提升舒适感，庭院围合优化空间体验，实现了“以人为本”的营造目标。 本次调研基于开平近代建筑考察工作坊的两大核心维度，系统完成了立园泮文楼的建造材料构造与尺度人体感知分析。研究证实，泮文楼以钢筋混凝土框架为结构核心、中西材料混搭为表皮特征、工业化与传统构造结合为工艺逻辑，同时以人体工程学为尺度基准、气候适配为功能目标、空间舒适为感知追求，是近代开平侨乡居住建筑的典范之作。 泮文楼的营造智慧，为现代建筑设计提供了三重启示：一是材料选型需优先适配地域气候；二是构造工艺应兼顾安全、效率与文化表达；三是尺度设计必须回归人体感知，实现功能与舒适的统一。本次调研成果不仅完成了工作坊的教学要求，更为开平近代建筑的保护、研究与现代转译提供了详实的实证数据。</p>',8)])])}const A=t(k,[["render",d]]);export{x as __pageData,A as default};
